import{_ as t,c as e,o as l,ag as i}from"./chunks/framework.dvv-DFtf.js";const u=JSON.parse('{"title":"Webmail 快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"webmail/quickstart.md","filePath":"webmail/quickstart.md","lastUpdated":null}'),r={name:"webmail/quickstart.md"};function o(d,a,n,s,c,h){return l(),e("div",null,[...a[0]||(a[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /webmail\\quickstart.md for this page in Markdown format</div><h1 id="webmail-快速开始" tabindex="-1">Webmail 快速开始 <a class="header-anchor" href="#webmail-快速开始" aria-label="Permalink to &quot;Webmail 快速开始&quot;">​</a></h1><h2 id="第一步-获取账号" tabindex="-1">第一步：获取账号 <a class="header-anchor" href="#第一步-获取账号" aria-label="Permalink to &quot;第一步：获取账号&quot;">​</a></h2><p>Webmail 账号由管理员统一创建。如需开通，联系：</p><ul><li><strong>邮件</strong>：admin@lurus.cn</li><li><strong>说明</strong>：提供姓名、部门，期望用户名（如 <code>zhangsan</code>）</li></ul><p>账号创建后你会收到一封含初始密码的欢迎邮件。</p><h2 id="第二步-登录-web-界面" tabindex="-1">第二步：登录 Web 界面 <a class="header-anchor" href="#第二步-登录-web-界面" aria-label="Permalink to &quot;第二步：登录 Web 界面&quot;">​</a></h2><ol><li>打开浏览器，访问 <a href="https://mail.lurus.cn" target="_blank" rel="noreferrer">mail.lurus.cn</a></li><li>输入邮箱地址（如 <code>zhangsan@lurus.cn</code>）和密码</li><li>点击「登录」</li></ol><div class="tip custom-block"><p class="custom-block-title">修改初始密码</p><p>首次登录后请立即修改密码：点击右上角头像 → 「账号设置」→「修改密码」</p></div><h2 id="第三步-发送第一封邮件" tabindex="-1">第三步：发送第一封邮件 <a class="header-anchor" href="#第三步-发送第一封邮件" aria-label="Permalink to &quot;第三步：发送第一封邮件&quot;">​</a></h2><ol><li>点击左上角「撰写」（或按 <code>C</code> 键）</li><li>填写收件人地址</li><li>输入主题和正文</li><li>点击「发送」</li></ol><h3 id="发送带附件的邮件" tabindex="-1">发送带附件的邮件 <a class="header-anchor" href="#发送带附件的邮件" aria-label="Permalink to &quot;发送带附件的邮件&quot;">​</a></h3><ol><li>撰写邮件界面，点击附件图标（回形针）</li><li>选择本地文件</li><li>等待上传完成后点击「发送」</li></ol><div class="warning custom-block"><p class="custom-block-title">附件大小限制</p><p>单封邮件附件总大小上限：<strong>25 MB</strong></p></div><h2 id="第四步-配置邮件过滤规则-可选" tabindex="-1">第四步：配置邮件过滤规则（可选） <a class="header-anchor" href="#第四步-配置邮件过滤规则-可选" aria-label="Permalink to &quot;第四步：配置邮件过滤规则（可选）&quot;">​</a></h2><p>「设置」→「过滤规则」，可设置：</p><ul><li>将特定发件人邮件自动归档到文件夹</li><li>自动转发到其他邮箱</li><li>自动回复（外出通知）</li></ul><p><strong>示例：将 GitHub 通知归档</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>条件：发件人包含 @github.com</span></span>
<span class="line"><span>动作：移动到文件夹「GitHub」</span></span></code></pre></div><h2 id="基本快捷键" tabindex="-1">基本快捷键 <a class="header-anchor" href="#基本快捷键" aria-label="Permalink to &quot;基本快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>C</code></td><td>撰写新邮件</td></tr><tr><td><code>R</code></td><td>回复</td></tr><tr><td><code>A</code></td><td>全部回复</td></tr><tr><td><code>F</code></td><td>转发</td></tr><tr><td><code>Del</code></td><td>删除</td></tr><tr><td><code>S</code></td><td>搜索</td></tr><tr><td><code>?</code></td><td>显示所有快捷键</td></tr></tbody></table><h2 id="手机端访问" tabindex="-1">手机端访问 <a class="header-anchor" href="#手机端访问" aria-label="Permalink to &quot;手机端访问&quot;">​</a></h2><p>Webmail 支持移动浏览器直接访问，也可通过以下方式配置 App：</p><ul><li><strong>iOS</strong>：使用系统邮件 App 或第三方 App（Canary Mail、Spark）</li><li><strong>Android</strong>：使用 Gmail App、K-9 Mail 或原生邮件 App</li></ul><p>配置参数见 <a href="/webmail/client-setup">客户端配置</a>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/webmail/client-setup">客户端配置</a> — 在 Outlook、Apple Mail 等客户端配置收发邮件</li><li><a href="/webmail/faq">常见问题</a> — 邮件无法送达、登录问题等排查</li></ul>`,27)])])}const b=t(r,[["render",o]]);export{u as __pageData,b as default};
